import React from 'react';
import './world-map.css';
import BattleMode from '../battle-mode/battle-mode'; // Import the BattleMode component
import mapsData from './maps.json';
import CountyTransition from '../county-transition/county-transition'


const countyTransitions = {
  westmeath: { tileNumber: 2, nextCounty: 'meath' },
  meath: { tileNumber: 3, nextCounty: 'westmeath' },
  // Add more transitions for other counties...
};

class Overworld extends React.Component {
  constructor(props) {
    super(props);

    this.state = {
      playerPosition: {
        row: 0,
        col: 0,
      },
      badGuyPosition: {
        row: 5,
        col: 5,
      },
      message: '',
      remainingMoves: 2,
      isBadGuyMoving: false,
      selectedMapIndex: 0, // Initialize the selected map index
    };
  }

  componentDidMount() {
    this.updateMessage();
    window.addEventListener('resize', this.handleResize);
  }

  componentWillUnmount() {
    window.removeEventListener('resize', this.handleResize);
  }

  updateMessage = () => {
    const message = window.innerWidth > window.innerHeight ? 'Landscape' : 'Portrait';
    this.setState({ message });
  };

  handleResize = () => {
    this.updateMessage();
  };

  canMove = (row, col) => {
    const { mapData } = this.props;
    const { remainingMoves } = this.state;
    return mapData[row][col] !== 9 && remainingMoves > 0;
  };



  handleTileTouch = (row, col) => {
    const { playerPosition, remainingMoves } = this.state;
    const rowDiff = Math.abs(row - playerPosition.row);
    const colDiff = Math.abs(col - playerPosition.col);

    if (rowDiff <= remainingMoves && colDiff <= remainingMoves) {
      if (this.canMove(row, col)) {
        const newRemainingMoves = remainingMoves - 1;

        if (newRemainingMoves === 0) {
          this.endTurn(); // Automatically end the turn
        } else {
          this.setState((prevState) => ({
            playerPosition: { row, col },
            remainingMoves: newRemainingMoves,
          }));
        }
      }
    }


  const tileValue = selectedMap.mapData[row][col];

  if (tileValue >= 2 && tileValue <= 9) {
    this.triggerCountyTransition(tileValue);
    return; // Don't proceed with regular movement logic
  }
  };

  getLocationName(selectedMap, playerPosition) {
    const { locations } = selectedMap;
    const tileValue = selectedMap.mapData[playerPosition.row][playerPosition.col];

    if (tileValue >= 30 && tileValue <= 35) {
      const locationIndex = tileValue - 30;
      return locations[locationIndex];
    }

    return '';
  }


  triggerCountyTransition = (tileValue) => {
    const { playerPosition } = this.state;
    const currentCounty = selectedMap.county;
    const transitionData = countyTransitions[currentCounty];

    if (transitionData && transitionData.tileNumber === tileValue) {
      const nextCounty = transitionData.nextCounty;
      // Load new background image and JSON data for the next county here
      // Update the state to reflect the new county
      this.setState({
        selectedMapIndex: mapsData.findIndex((map) => map.county === nextCounty),
        // Other relevant state updates...
      });

      // Render the transition component here
      this.setState({ isTransitioning: true });
      setTimeout(() => {
        this.setState({ isTransitioning: false });
      }, 2000); // Delay for transition animation
    }
  };

  endTurn = () => {
    this.setState(
      {
        remainingMoves: 2,
        isBadGuyMoving: true,
      },
      () => {
        this.moveBadGuy(); // Move the bad guy after the player's turn
        setTimeout(() => {
          this.setState({ isBadGuyMoving: false });
        }, 1000); // Delay for bad guy movement
      }
    );
  };

  moveBadGuy = () => {
    const { badGuyPosition } = this.state;
    const newBadGuyPosition = { ...badGuyPosition };

    // Implement your logic to move the bad guy
    // For example, move towards the player's position
    if (newBadGuyPosition.row < this.state.playerPosition.row) {
      newBadGuyPosition.row += 1;
    } else if (newBadGuyPosition.row > this.state.playerPosition.row) {
      newBadGuyPosition.row -= 1;
    }

    if (newBadGuyPosition.col < this.state.playerPosition.col) {
      newBadGuyPosition.col += 1;
    } else if (newBadGuyPosition.col > this.state.playerPosition.col) {
      newBadGuyPosition.col -= 1;
    }

    this.setState({ badGuyPosition: newBadGuyPosition });
  };

  handleBattleClose = () => {
    this.setState({
      badGuyPosition: null,
    });
  };

  endTurn = () => {
    this.setState(
      {
        remainingMoves: 2,
        isBadGuyMoving: true,
      },
      () => {
        this.moveBadGuy();
        setTimeout(() => {
          this.setState({ isBadGuyMoving: false });
        }, 1000);
      }
    );
  };

  renderGameBoard() {
    const { playerPosition, badGuyPosition, selectedMapIndex } = this.state;
    const selectedMap = mapsData[selectedMapIndex];

    return selectedMap.mapData.map((row, rowIndex) => (
      <div key={`row-${rowIndex}`} className="game-row">
        {row.map((tile, colIndex) => {
          const isPlayerTile = rowIndex === playerPosition.row && colIndex === playerPosition.col;
          const isBadGuyTile = badGuyPosition && rowIndex === badGuyPosition.row && colIndex === badGuyPosition.col;
          const rowDiff = Math.abs(rowIndex - playerPosition.row);
          const colDiff = Math.abs(colIndex - playerPosition.col);
          const isHighlighted = rowDiff <= this.state.remainingMoves && colDiff <= this.state.remainingMoves;

          let content = null;

          if (tile === 0) {
            content = <div className="obstacle"></div>;
          } else if (tile >= 30 && tile <= 35 && isPlayerTile) {
            const locationIndex = tile - 30; // Adjust to get the correct index
            content = <div className="square-number">{selectedMap.locations[locationIndex]}</div>;
          } else {
            content = <div className="square-number">{tile}</div>;
          }

          return (
            <div
              key={`tile-${rowIndex}-${colIndex}`}
              className={`game-tile ${tile === 9 ? 'non-walkable' : ''} ${
                isPlayerTile ? 'player-icon' : ''
              } ${isBadGuyTile ? 'bad-guy-icon' : ''} ${isHighlighted ? 'highlighted' : ''}`}
              onTouchStart={() => this.handleTileTouch(rowIndex, colIndex)}
            >
              {content}
            </div>
          );
        })}
      </div>
    ));
  }

  render() {


    const { isTransitioning, /* other state values */ } = this.state;

    const { message, isBadGuyMoving, playerPosition, badGuyPosition, isBattleMode, selectedMapIndex } = this.state;
    const selectedMap = mapsData[selectedMapIndex];
    const { locations } = selectedMap; // Get the locations array from the selected map

    return (
      <div className="world-map-container">
        <h1>{message}</h1>
        <h2>{this.getLocationName(selectedMap, playerPosition)}</h2>
        <div className="world-map">
          {this.renderGameBoard()}
          {badGuyPosition && playerPosition.row === badGuyPosition.row && playerPosition.col === badGuyPosition.col && (
            <BattleMode onCloseBattle={this.handleBattleClose} />
          )}
        </div>
        <button onClick={this.endTurn} disabled={isBadGuyMoving || isBattleMode}>
          End Turn
        </button>

        {isTransitioning && <CountyTransition />}
      </div>
    );
  }

}

export default Overworld;
